import type { TimeGranularity, TimeSeriesPoint } from '../models/analytics.js';

/**
 * Get the start of the bucket a date falls into, based on granularity.
 */
function getBucketStart(date: Date, granularity: TimeGranularity): Date {
  const d = new Date(date);
  switch (granularity) {
    case 'hour':
      d.setMinutes(0, 0, 0);
      return d;
    case 'day':
      d.setHours(0, 0, 0, 0);
      return d;
    case 'week': {
      d.setHours(0, 0, 0, 0);
      const day = d.getDay();
      d.setDate(d.getDate() - day);
      return d;
    }
    case 'month':
      d.setHours(0, 0, 0, 0);
      d.setDate(1);
      return d;
  }
}

/**
 * Advance a date by one granularity unit.
 */
function advanceBucket(date: Date, granularity: TimeGranularity): Date {
  const d = new Date(date);
  switch (granularity) {
    case 'hour':
      d.setHours(d.getHours() + 1);
      return d;
    case 'day':
      d.setDate(d.getDate() + 1);
      return d;
    case 'week':
      d.setDate(d.getDate() + 7);
      return d;
    case 'month':
      d.setMonth(d.getMonth() + 1);
      return d;
  }
}

/**
 * Bucket items into time-series points by granularity.
 *
 * Each item is assigned to a bucket based on its date (via `getDate`).
 * The `getValue` function extracts the numeric value to sum within each bucket.
 * Empty buckets within the range are included with value 0.
 */
export function bucketByTime<T>(
  items: T[],
  getDate: (item: T) => Date,
  getValue: (item: T) => number,
  granularity: TimeGranularity,
  start: Date,
  end: Date,
): TimeSeriesPoint[] {
  // Build all bucket boundaries
  const buckets = new Map<string, number>();
  let cursor = getBucketStart(new Date(start), granularity);
  while (cursor <= end) {
    buckets.set(cursor.toISOString(), 0);
    cursor = advanceBucket(cursor, granularity);
  }

  // Assign items to buckets
  for (const item of items) {
    const bucketStart = getBucketStart(getDate(item), granularity);
    const key = bucketStart.toISOString();
    if (buckets.has(key)) {
      buckets.set(key, buckets.get(key)! + getValue(item));
    }
  }

  // Convert to sorted TimeSeriesPoint array
  const points: TimeSeriesPoint[] = [];
  for (const [key, value] of buckets) {
    points.push({ timestamp: new Date(key), value });
  }
  points.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
  return points;
}

