parameters.new_string:
private buildOrderAnalytics(orders: Order[], query: AnalyticsQuery): OrderAnalytics {
  const totalOrders = orders.length;
  const totalRevenue = orders.reduce((sum, o) => sum + o.total, 0);
  const averageOrderValue = totalOrders > 0 ? totalRevenue / totalOrders : 0;

  const statusBreakdown: OrderStatusBreakdown = {
    pending: 0,
    confirmed: 0,
    shipped: 0,
    delivered: 0,
    cancelled: 0,
  };
  for (const order of orders) {
    statusBreakdown[order.status as OrderStatus]++;
  }

  const { start, end } = query.timeRange;
  const revenueSeries: TimeSeries = {
    label: 'revenue',
    points: bucketByTime(orders, (o) => o.createdAt, (o) => o.total, query.granularity, start, end),
  };
  const orderCountSeries: TimeSeries = {
    label: 'orders',
    points: bucketByTime(orders, (o) => o.createdAt, () => 1, query.granularity, start, end),
  };

  return {
    totalOrders,
    totalRevenue,
    averageOrderValue,
    statusBreakdown,
    revenueSeries,
    orderCountSeries,
  };
}

