parameters.new_string:
private buildUserAnalytics(users: User[], query: AnalyticsQuery): UserAnalytics {
  const totalUsers = this.userRepository.findAll().length;
  const newUsers = users.length;

  const usersByRole: Record<string, number> = {};
  for (const user of users) {
    usersByRole[user.role] = (usersByRole[user.role] ?? 0) + 1;
  }

  const { start, end } = query.timeRange;
  const newUserSeries: TimeSeries = {
    label: 'newUsers',
    points: bucketByTime(users, (u) => u.createdAt, () => 1, query.granularity, start, end),
  };

  return { totalUsers, newUsers, usersByRole, newUserSeries };
}

