private buildMetricSummaries(
  orderAnalytics: OrderAnalytics,
  userAnalytics: UserAnalytics,
  query: AnalyticsQuery,
): MetricSummary[] {
  // Compute previous period by shifting the time range backwards by its own length
  const durationMs = query.timeRange.end.getTime() - query.timeRange.start.getTime();
  const previousTimeRange: TimeRange = {
    start: new Date(query.timeRange.start.getTime() - durationMs),
    end: new Date(query.timeRange.start.getTime()),
  };
  const previousQuery: AnalyticsQuery = { timeRange: previousTimeRange, granularity: query.granularity };

  const prevOrders = this.getOrdersInRange(previousQuery);
  const prevUsers = this.getUsersInRange(previousQuery);
  const prevOrderAnalytics = this.buildOrderAnalytics(prevOrders, previousQuery);
  const prevUserAnalytics = this.buildUserAnalytics(prevUsers, previousQuery);

  const computeChange = (current: number, previous: number): number => {
    if (previous === 0) return 0;
    return ((current - previous) / previous) * 100;
  };

  return [
    {
      type: 'revenue',
      currentValue: orderAnalytics.totalRevenue,
      previousValue: prevOrderAnalytics.totalRevenue,
      change: computeChange(orderAnalytics.totalRevenue, prevOrderAnalytics.totalRevenue),
      timeSeries: orderAnalytics.revenueSeries,
    },
    {
      type: 'orders',
      currentValue: orderAnalytics.totalOrders,
      previousValue: prevOrderAnalytics.totalOrders,
      change: computeChange(orderAnalytics.totalOrders, prevOrderAnalytics.totalOrders),
      timeSeries: orderAnalytics.orderCountSeries,
    },
    {
      type: 'users',
      currentValue: userAnalytics.newUsers,
      previousValue: prevUserAnalytics.newUsers,
      change: computeChange(userAnalytics.newUsers, prevUserAnalytics.newUsers),
      timeSeries: userAnalytics.newUserSeries,
    },
    {
      type: 'average-order-value',
      currentValue: orderAnalytics.averageOrderValue,
      previousValue: prevOrderAnalytics.averageOrderValue,
      change: computeChange(orderAnalytics.averageOrderValue, prevOrderAnalytics.averageOrderValue),
      timeSeries: orderAnalytics.revenueSeries,
    },
  ];
}

